const amqp = require('amqplib');

async function createPaymentConsumer() {
  try {
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();
    
    const queue = 'payment_events';
    await channel.assertQueue(queue, { durable: true });
    
    channel.prefetch(1);
    
    channel.consume(queue, async (msg) => {
      if (msg !== null) {
        try {
          const paymentData = JSON.parse(msg.content.toString());
          
          // Process payment logic directly
          await processPayment(paymentData);
          
          channel.ack(msg);
        } catch (error) {
          console.error('Payment processing error:', error);
          channel.nack(msg, false, false);
        }
      }
    });
    
    console.log('Payment consumer started');
  } catch (error) {
    console.error('Failed to start payment consumer:', error);
  }
}

async function processPayment(paymentData) {
  // Direct payment processing logic
  console.log('Processing payment:', paymentData);
  
  // Simulate payment processing
  await new Promise(resolve => setTimeout(resolve, 1000));
  
  console.log('Payment processed successfully');
}

createPaymentConsumer();